class Solution {
public:
    int minStartingIndex(string s, string pattern) {
        int n = s.size(), m = pattern.size();
        int diffCount = 0;
        for (int i = 0; i < m; ++i) {
            if (s[i] != pattern[i]) {
                ++diffCount;
            }
        }
        if (diffCount <= 1) {
            return 0;
        }
        for (int i = m; i < n; ++i) {
            if (s[i] != pattern[i - m]) {
                ++diffCount;
            }
            if (s[i - m] != pattern[i - m]) {
                --diffCount;
            }
            if (diffCount <= 1) {
                return i - m + 1;
            }
        }
        return -1;
    }
};
